mapper.select:
SELECT

FROM outsource_workload w


    w.deleted = 0

        AND ot.agent_company_id = #{query.agentCompanyId}


        AND ot.project_id = #{query.projectId}


        AND w.status = #{query.status}


        AND w.create_time >= CONCAT(#{query.beginTime}, ' 00:00:00')


        AND w.create_time < DATE_ADD(CONCAT(#{query.endTime}, ' 00:00:00'), INTERVAL 1 DAY)


ORDER BY w.create_time DESC
